import{_ as s,c as n,o as a,a as e}from"./app.75fe7403.js";const D=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[{"level":2,"title":"Installation","slug":"installation","link":"#installation","children":[]},{"level":2,"title":"qfconfig.json, at the root of your project","slug":"qfconfig-json-at-the-root-of-your-project","link":"#qfconfig-json-at-the-root-of-your-project","children":[]},{"level":2,"title":"QueryFirstConnectionFactory","slug":"queryfirstconnectionfactory","link":"#queryfirstconnectionfactory","children":[]},{"level":2,"title":"Create a query","slug":"create-a-query","link":"#create-a-query","children":[]}],"relativePath":"getting-started.md"}'),t={name:"getting-started.md"},o=e(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-hidden="true">#</a></h1><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-hidden="true">#</a></h2><p>QueryFirst is primarily a Visual Studio extension. Changing requirements for extensions mean that we currently maintain separate versions for VS 2019 and VS2022. You can install directly inside Visual Studio (Extensions =&gt; Manage Extensions, then search for QueryFirst) or you can download from the marketplace, taking the time to browse the QA and reviews.</p><ul><li><a href="https://marketplace.visualstudio.com/items?itemName=bbsimonbb.QueryFirst" target="_blank" rel="noreferrer">VS 2019 on the VS marketplace</a></li><li><a href="https://marketplace.visualstudio.com/items?itemName=bbsimonbb.QueryFirstVS17" target="_blank" rel="noreferrer">QueryFirst for VS 2022</a></li></ul><p>To Use QueryFirst in a project you will need to create a qfconfig.json file and implement the QueryFirstConnectionFactory abstract class.</p><h2 id="qfconfig-json-at-the-root-of-your-project" tabindex="-1">qfconfig.json, at the root of your project <a class="header-anchor" href="#qfconfig-json-at-the-root-of-your-project" aria-hidden="true">#</a></h2><p>This is where you tell QueryFirst what database to use for test-running your query and generating the C# wrapper.</p><div class="language-json"><button class="copy"></button><span class="lang">json</span><pre><code><span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C792EA;">defaultConnection</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Data Source=localhost;Initial Catalog=Northwind;Integrated Security=True</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"></span></code></pre></div><h2 id="queryfirstconnectionfactory" tabindex="-1">QueryFirstConnectionFactory <a class="header-anchor" href="#queryfirstconnectionfactory" aria-hidden="true">#</a></h2><p>QueryFirst repositories will use this class to get their runtime database connections. You can copy this class into your project, or you can import it via the QueryFirst.Runtime nuget. You then need to subclass it and implement the <code>CreateConnection()</code> method. If you instantiate your QfRepos, supply your subclassed QueryFirstConnectionFactory to the constructor, or register it as a service and let DI take care of it. If you plan to use the static methods on your repositories, you need to assign the Instance property.</p><div class="language-csharp"><button class="copy"></button><span class="lang">csharp</span><pre><code><span class="line"><span style="color:#F78C6C;">using</span><span style="color:#A6ACCD;"> System.Data</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#F78C6C;">using</span><span style="color:#A6ACCD;"> System.Data.SqlClient</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F78C6C;">namespace</span><span style="color:#A6ACCD;"> QueryFirst</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">abstract</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">class</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">QueryFirstConnectionFactory</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">abstract</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">IDbConnection</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">CreateConnection</span><span style="color:#89DDFF;">();</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">static</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">QueryFirstConnectionFactory</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">Instance</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">get</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">set</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F78C6C;">namespace</span><span style="color:#A6ACCD;"> MySuperProject</span></span>
<span class="line"><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">class</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">MyDB</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">QueryFirst</span><span style="color:#89DDFF;">.</span><span style="color:#FFCB6B;">QueryFirstConnectionFactory</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#C792EA;">public</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">override</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">IDbConnection</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">CreateConnection</span><span style="color:#89DDFF;">()</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">            </span><span style="color:#89DDFF;">return</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">SqlConnection</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Data Source=my_db_server;Database=Northwind;Trusted_Connection=True;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">);</span></span>
<span class="line"><span style="color:#A6ACCD;">        </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">}</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;">// then, to use the static methods, in your startup code you will need to instantiate and assign...</span></span>
<span class="line"><span style="color:#A6ACCD;">QueryFirst</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">QueryFirstConnectionFactory</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">Instance </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#C792EA;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">MyDB</span><span style="color:#89DDFF;">();</span></span>
<span class="line"></span></code></pre></div><h2 id="create-a-query" tabindex="-1">Create a query <a class="header-anchor" href="#create-a-query" aria-hidden="true">#</a></h2><p>QueryFirst queries live in .sql files, created with the QueryFirst template that you should now see under Add =&gt; New items =&gt; Visual C#.</p><p>Once in the template, your query goes after the <code>-- endDesignTime</code> flag.</p><p><img src="https://user-images.githubusercontent.com/11962703/75419461-f7bd6e80-5989-11ea-93c9-583105e261d3.png" alt="QueryFirst template"></p><p>If this is too slow for you, and you&#39;re in a .net core project (.net 5 or greater), you can just create a .sql file and put the text &quot;queryfirst&quot; (case insensitive) somewhere on the first line. Use the <a href="https://marketplace.visualstudio.com/items?itemName=MadsKristensen.AddNewFile" target="_blank" rel="noreferrer">Add New File</a> extension until its functionality <a href="https://twitter.com/mkristensen/status/1561823791553998848" target="_blank" rel="noreferrer">finally shows up in visual studio</a>.</p>`,16),l=[o];function r(p,c,i,y,C,u){return a(),n("div",null,l)}const A=s(t,[["render",r]]);export{D as __pageData,A as default};
